import java.util.*;
public class T2Final {
    static List<List<String>> grp(String[] s){Map<String,List<String>> m=new HashMap<>();for(String w:s){char[]c=w.toCharArray();Arrays.sort(c);m.computeIfAbsent(new String(c),k->new ArrayList<>()).add(w);}return new ArrayList<>(m.values());}
    static int[] topK(int[] n,int k){Map<Integer,Integer> f=new HashMap<>();for(int x:n)f.merge(x,1,Integer::sum);PriorityQueue<Integer> pq=new PriorityQueue<>(Comparator.comparingInt(f::get));for(int x:f.keySet()){pq.offer(x);if(pq.size()>k)pq.poll();}int[]r=new int[k];for(int i=k-1;i>=0;i--)r[i]=pq.poll();return r;}
    static String minWin(String s,String t){int[] nd=new int[128],wd=new int[128];for(char c:t.toCharArray())nd[c]++;int req=t.length(),lo=0,ml=Integer.MAX_VALUE,ms=0;for(int hi=0;hi<s.length();hi++){char c=s.charAt(hi);wd[c]++;if(nd[c]>0&&wd[c]<=nd[c])req--;while(req==0){if(hi-lo+1<ml){ml=hi-lo+1;ms=lo;}char l=s.charAt(lo);wd[l]--;if(nd[l]>0&&wd[l]<nd[l])req++;lo++;}}return ml==Integer.MAX_VALUE?"":s.substring(ms,ms+ml);}
